svn_get_branch_name() {
  local info branch
  info="${1:-$(LANG= svn info 2>/dev/null)}"
  branch=$(
    awk -F/ '/^URL:/ {
      for (i=0; i<=NF; i++) {
        if ($i == "branches" || $i == "tags" ) {
          print $(i+1)
          break
        };
        if ($i == "trunk") {
          print $i
          break
        }
      }
    }' <<< "$info"
  )
  branch="$(omz_urldecode "$branch")"

  echo "${branch:-$(svn_get_repo_name "$info")}"
}

